```tsx
export default function Dashboard({ userId }) {
  const [d, setD] = useState(null);
  const [l, setL] = useState(true);
  const [e, setE] = useState(null);
  const [f, setF] = useState('all');

  useEffect(() => {
    // fetch data
    setL(true);
    fetch(`/api/users/${userId}/stats`)
      .then(r => r.json())
      .then(data => { setD(data); setL(false); })
      .catch(err => { setE(err.message); setL(false); });
  }, [userId]);

  if (l) return <div>Loading...</div>;
  if (e) return <div>Error: {e}</div>;
  if (!d) return null;

  // filter
  const filtered = f === 'all' ? d.items : d.items.filter(i => i.category === f);
  // calc total
  const total = filtered.reduce((s, i) => s + i.amount, 0);
  // calc avg
  const avg = filtered.length > 0 ? total / filtered.length : 0;

  return (
    <div>
      <h1>Dashboard</h1>
      <select value={f} onChange={e => setF(e.target.value)}>
        <option value="all">All</option>
        {[...new Set(d.items.map(i => i.category))].map(c => (
          <option key={c} value={c}>{c}</option>
        ))}
      </select>
      <div>
        <div>Total: ${total.toFixed(2)}</div>
        <div>Average: ${avg.toFixed(2)}</div>
        <div>Count: {filtered.length}</div>
      </div>
      <ul>
        {filtered.map(i => (
          <li key={i.id}>{i.name} - ${i.amount.toFixed(2)} ({i.category})</li>
        ))}
      </ul>
    </div>
  );
}
```
